#ifndef DHT22_TEMPERATURE_HUMIDITY_H
#define DHT22_TEMPERATURE_HUMIDITY_H

#include <DHT.h>

class DHT22TemperatureHumidity {
public:
    void setup(uint8_t pin, uint32_t read_interval);
    float getTemperature();
    float getHumidity();

private:
    DHT dht;
    uint8_t _pin;
    uint32_t _read_interval;
    unsigned long _last_read_time = 0;
    float _temperature = NAN;
    float _humidity = NAN;

    void readSensor();
};

#endif // DHT22_TEMPERATURE_HUMIDITY_H

