#include "dht22_temperature_humidity.h"

void DHT22TemperatureHumidity::setup(uint8_t pin, uint32_t read_interval) {
    _pin = pin;
    _read_interval = read_interval;

    dht.begin(_pin, DHT22);

    // Retry logic for sensor initialization
    unsigned long start_time = millis();
    while (millis() - start_time < 5000 && !dht.readHumidity()) {
        delay(100);
        Serial.println("[dht22_temperature_humidity] Initialization failed, retrying...");
    }

    if (!isnan(dht.readHumidity())) {
        Serial.println("[dht22_temperature_humidity] Initialization successful");
    } else {
        Serial.println("[dht22_temperature_humidity] Initialization failed after retries");
    }
}

float DHT22TemperatureHumidity::getTemperature() {
    return _temperature;
}

float DHT22TemperatureHumidity::getHumidity() {
    return _humidity;
}

void DHT22TemperatureHumidity::readSensor() {
    unsigned long current_time = millis();
    if (current_time - _last_read_time >= _read_interval) {
        _last_read_time = current_time;

        float humidity = dht.readHumidity();
        float temperature = dht.readTemperature();

        if (isnan(humidity) || isnan(temperature)) {
            Serial.println("[dht22_temperature_humidity] Failed to read from sensor");
        } else {
            _temperature = temperature;
            _humidity = humidity;
            Serial.print("[dht22_temperature_humidity] Temperature: ");
            Serial.print(_temperature);
            Serial.print("°C, Humidity: ");
            Serial.print(_humidity);
            Serial.println("%RH");
        }
    }
}
